import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const VendorRegister = () => {
  const navigate = useNavigate();

  const [vendorData, setVendorData] = useState({
    vendor_name: '',
    // Add other fields as necessary
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setVendorData({ ...vendorData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:6000/vendor/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(vendorData),
      });
      if (!response.ok) throw new Error('Vendor registration failed');
      // Reset form or handle success
      setVendorData({ vendor_name: '' });
      navigate('/vendor/manage'); // Adjust the navigate path as needed
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div>
      <h1>出店者用のアカウント登録画面</h1>
      <form onSubmit={handleSubmit}>
        <label>
          Vendor Name:
          <input
            type="text"
            name="vendor_name"
            value={vendorData.vendor_name}
            onChange={handleInputChange}
            required
          />
        </label>
        {/* Add other input fields as necessary */}
        <button type="submit">Register Vendor</button>
      </form>
    </div>
  );
};

export default VendorRegister;
